            4,      // maximumPoolSize (최대 스레드 수)
            60L,    // keepAliveTime (유휴 스레드 대기 시간)
            TimeUnit.SECONDS,  // 시간 단위
            new LinkedBlockingQueue<>(2),  // 작업 큐 (용량 2)
            new ThreadPoolExecutor.CallerRunsPolicy()  // 거부 정책: 호출자 스레드에서 실행
        );

        // 2. 작업 제출 (Runnable 또는 Callable)
        for (int i = 0; i < 6; i++) {
            final int taskId = i;
            executor.execute(() -> {
                System.out.println("Task " + taskId + " 실행 중 - " + Thread.currentThread().getName());
                try {
                    Thread.sleep(2000);  // 작업 시뮬레이션
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            });
        }

        // 3. 스레드 풀 종료
        executor.shutdown();  // 작업 완료 후 종료
        try {
            if (!executor.awaitTermination(5, TimeUnit.SECONDS)) {
                executor.shutdownNow();  // 강제 종료
